external_knowledge:
* This query assumes that a "client" refers to an individual or entity that has made one or more investments;
* "Total investment amount" is the sum of all amounts a client has invested;
* "Average return on investment" is the mean return a client has received across all their investments;
* "Total return" refers to the sum of all returns a client has received from their investments.

sql:
SELECT advisor_name
FROM financial_advisors
WHERE experience_years > 10;

SELECT transaction_id, COUNT(*) AS total_premiums
FROM premiums
GROUP BY transaction_id;

SELECT client_id
FROM clients
WHERE client_id NOT IN (
  SELECT client_id
  FROM investments
);
